from collections import defaultdict
from sys import stdin
from heapq import heappop, heappush
from math import inf

class Solution:
    def hamiltonianCycle(self, graph: List[List[Tuple[int, int]]], src: int) -> int:
        V = len(graph)
        minWeight = float('inf')
		# Initialize distance array with infinity
        distance = [inf] * V
        distance[src] = 0
        predecessor = [-1] * V
		# Relax edges repeatedly
        for _ in range(V - 1):
            for u in range(V):
                for v, weight in graph[u]:
                    if distance[u] + weight < distance[v]:
                        distance[v] = distance[u] + weight
                        predecessor[v] = u
		# Check for negative weight cycles
        for u in range(V):
            for v, weight in graph[u]:
                if distance[u] + weight < distance[v]:
                    return -1
		# Check for Hamiltonian Cycle
        for u in range(V):
            if distance[u] == inf:
			# If a vertex has infinite distance, it means we have not visited it yet
                break
        else:
            return -1
		# Reconstruct the Hamiltonian Cycle
        cycleWeight = 0
        u = src
        for _ in range(V):
            v = predecessor[u]
            cycleWeight += graph[u][v][1]
            u = v
        return cycleWeight

